export const styleSheetText = "/* IPL Playoff Probability Tracker — Cricbuzz-aligned styling.\n * Per resolved decision #4: Inter for the table (cricbuzz match), Fraunces for hero (differentiation).\n * The memorable move: each row's background is a CSS gradient driven by --p (P(playoffs) %),\n * filling the row in green. Pure CSS, no JS, no client-side state.\n */\n\n@font-face {\n  font-family: \"Inter\";\n  font-style: normal;\n  font-weight: 400 700;\n  font-display: swap;\n  src: local(\"Inter\"), url(\"/fonts/Inter-Variable.woff2\") format(\"woff2-variations\");\n}\n@font-face {\n  font-family: \"Fraunces\";\n  font-style: normal;\n  font-weight: 400 800;\n  font-display: swap;\n  src: local(\"Fraunces\"), url(\"/fonts/Fraunces-Variable.woff2\") format(\"woff2-variations\");\n}\n\n:root {\n  /* Cricbuzz palette — extracted from production CSS */\n  --cb-green:        #009270;\n  --cb-green-hover:  #028062;\n  --cb-green-deep:   #07794c;\n  --cb-tint:         #ebf9f6;\n  --cb-row-alt:      #fafafa;\n  --cb-border:       #ecebeb;\n  --cb-header-bg:    #212121;\n  --cb-text-primary: #222;\n  --cb-text-muted:   #666;\n  --cb-text-faint:   #959595;\n  --cb-live-red:     #e90b37;\n  --cb-stale-amber:  #f4a261;\n\n  --bar-track:       color-mix(in srgb, var(--cb-green) 9%, white);\n  --bar-track-hi:    color-mix(in srgb, var(--cb-green) 16%, white);\n\n  --serif: \"Fraunces\", \"Source Serif Pro\", Georgia, serif;\n  --sans:  \"Inter\", ui-sans-serif, system-ui, -apple-system, \"Segoe UI\", Roboto, \"Helvetica Neue\", Arial, sans-serif;\n\n  --font-feature-tnum: \"tnum\" 1, \"lnum\" 1;\n}\n\n* { box-sizing: border-box; }\nhtml { background: #ffffff; }\nbody {\n  margin: 0;\n  font-family: var(--sans);\n  color: var(--cb-text-primary);\n  font-size: 15px;\n  line-height: 1.5;\n  -webkit-font-smoothing: antialiased;\n  -moz-osx-font-smoothing: grayscale;\n}\n\nmain {\n  max-width: 980px;\n  margin: 0 auto;\n  padding: 24px 20px 60px;\n}\n\n@view-transition { navigation: auto; }\n\n/* --------- Hero --------- */\n.dateline {\n  font-size: 11px;\n  letter-spacing: 0.08em;\n  text-transform: uppercase;\n  color: var(--cb-text-faint);\n  font-weight: 600;\n}\n.dateline .sep { color: var(--cb-border); margin: 0 8px; }\n\n.headline {\n  font-family: var(--serif);\n  font-weight: 800;\n  font-size: clamp(34px, 6.5vw, 56px);\n  line-height: 1.05;\n  letter-spacing: -0.02em;\n  margin: 6px 0 6px;\n  color: var(--cb-text-primary);\n}\n.headline em { font-style: italic; color: var(--cb-green-deep); }\n\n.kicker {\n  font-size: 14px;\n  color: var(--cb-text-muted);\n  max-width: 60ch;\n  margin: 0 0 16px;\n}\n\n/* --------- Staleness banner --------- */\n.banner {\n  display: flex;\n  align-items: center;\n  gap: 10px;\n  padding: 10px 14px;\n  border-radius: 6px;\n  font-size: 13px;\n  font-weight: 500;\n  margin-bottom: 18px;\n}\n.banner-dot { width: 8px; height: 8px; border-radius: 50%; flex-shrink: 0; }\n.banner.fresh { background: var(--cb-tint); color: var(--cb-green-deep); }\n.banner.fresh .banner-dot { background: var(--cb-green); }\n.banner.amber { background: #fff3e0; color: #8a4400; }\n.banner.amber .banner-dot { background: var(--cb-stale-amber); }\n.banner.red   { background: #fbeaea; color: #8a0d0d; }\n.banner.red   .banner-dot { background: var(--cb-live-red); }\n.banner .right { margin-left: auto; font-size: 12px; opacity: 0.75; }\n.banner a { color: inherit; text-decoration: underline; }\n\n/* --------- Time-travel picker --------- */\n.tt {\n  display: flex;\n  flex-wrap: wrap;\n  align-items: center;\n  gap: 8px;\n  margin-bottom: 14px;\n}\n.tt-label {\n  font-size: 11px;\n  letter-spacing: 0.08em;\n  text-transform: uppercase;\n  font-weight: 600;\n  color: var(--cb-text-faint);\n  margin-right: 6px;\n}\n.tt-pill {\n  display: inline-block;\n  padding: 5px 10px;\n  border: 1px solid var(--cb-border);\n  border-radius: 999px;\n  font-size: 12px;\n  font-weight: 500;\n  color: var(--cb-text-primary);\n  text-decoration: none;\n  background: white;\n}\n.tt-pill:hover, .tt-pill:focus { background: var(--cb-tint); border-color: var(--cb-green); }\n.tt-pill.active {\n  background: var(--cb-green);\n  color: white;\n  border-color: var(--cb-green);\n}\n.tt-pill.back-to-live {\n  margin-left: auto;\n  background: var(--cb-green-deep);\n  color: white;\n  border-color: var(--cb-green-deep);\n}\n.tt form {\n  display: inline-flex;\n  align-items: center;\n  gap: 6px;\n  font-size: 12px;\n  color: var(--cb-text-muted);\n}\n.tt input[type=\"date\"] {\n  padding: 4px 8px;\n  border: 1px solid var(--cb-border);\n  border-radius: 4px;\n  font: inherit;\n  color: var(--cb-text-primary);\n  background: white;\n}\n.tt button {\n  padding: 5px 10px;\n  border-radius: 999px;\n  border: 1px solid var(--cb-border);\n  background: white;\n  font-size: 12px;\n  cursor: pointer;\n}\n\n/* --------- Main probability table --------- */\n.table-wrap { border: 1px solid var(--cb-border); border-radius: 6px; overflow: hidden; }\ntable.prob {\n  width: 100%;\n  border-collapse: collapse;\n  font-feature-settings: var(--font-feature-tnum);\n}\ntable.prob thead th {\n  background: var(--cb-header-bg);\n  color: white;\n  font-weight: 600;\n  font-size: 12px;\n  letter-spacing: 0.04em;\n  padding: 12px;\n  text-align: right;\n}\ntable.prob thead th.team-col { text-align: left; padding-left: 16px; }\ntable.prob thead th.rank-col { text-align: center; width: 36px; padding: 12px 6px; }\n\ntable.prob tbody tr {\n  /* --p drives the row-bar fill (0..100) */\n  --p: 0;\n  background-image: linear-gradient(\n    90deg,\n    var(--bar-track) calc(var(--p) * 1%),\n    transparent calc(var(--p) * 1%)\n  );\n  background-color: white;\n}\ntable.prob tbody tr:nth-child(even) {\n  background-color: var(--cb-row-alt);\n}\n@media (hover: hover) {\n  table.prob tbody tr:hover {\n    background-image: linear-gradient(\n      90deg,\n      var(--bar-track-hi) calc(var(--p) * 1%),\n      transparent calc(var(--p) * 1%)\n    );\n  }\n}\n\ntable.prob td {\n  padding: 11px 12px;\n  border-top: 1px solid var(--cb-border);\n  font-size: 14px;\n  text-align: right;\n  color: var(--cb-text-primary);\n}\ntable.prob td.team {\n  text-align: left;\n  padding-left: 16px;\n  font-weight: 600;\n}\ntable.prob td.rank {\n  text-align: center;\n  width: 36px;\n  padding: 11px 6px;\n  font-size: 13px;\n  color: var(--cb-text-muted);\n}\ntable.prob td .badge {\n  font-size: 10px;\n  font-weight: 700;\n  letter-spacing: 0.06em;\n  margin-left: 6px;\n  padding: 2px 6px;\n  border-radius: 3px;\n  background: var(--cb-green);\n  color: white;\n  vertical-align: middle;\n}\ntable.prob td .badge.elim {\n  background: var(--cb-border);\n  color: var(--cb-text-muted);\n}\ntable.prob td.num {\n  font-variant-numeric: tabular-nums;\n  font-weight: 500;\n  position: relative;\n}\ntable.prob td.num.zero { color: var(--cb-text-faint); }\n\n/* --------- Champion cross-check --------- */\n.cross {\n  margin-top: 32px;\n  background: white;\n  border: 1px solid var(--cb-border);\n  border-radius: 6px;\n  overflow: hidden;\n}\n.cross h2 {\n  margin: 0;\n  padding: 14px 16px;\n  background: var(--cb-tint);\n  border-bottom: 1px solid var(--cb-border);\n  font-size: 14px;\n  font-weight: 700;\n  letter-spacing: 0.03em;\n  text-transform: uppercase;\n  color: var(--cb-green-deep);\n}\n.cross table { width: 100%; border-collapse: collapse; }\n.cross th {\n  padding: 8px 12px;\n  font-size: 11px;\n  font-weight: 600;\n  letter-spacing: 0.05em;\n  text-transform: uppercase;\n  color: var(--cb-text-muted);\n  text-align: right;\n  border-bottom: 1px solid var(--cb-border);\n}\n.cross th.team-col { text-align: left; padding-left: 16px; }\n.cross td {\n  padding: 8px 12px;\n  font-size: 13px;\n  text-align: right;\n  font-variant-numeric: tabular-nums;\n  border-top: 1px solid var(--cb-border);\n}\n.cross td.team-col { text-align: left; padding-left: 16px; font-weight: 600; }\n.cross td.delta.warn { color: #b35900; font-weight: 600; }\n\n/* --------- Footer --------- */\nfooter {\n  margin-top: 40px;\n  padding-top: 18px;\n  border-top: 1px solid var(--cb-border);\n  font-size: 11px;\n  color: var(--cb-text-faint);\n  line-height: 1.6;\n}\nfooter .sources a { color: var(--cb-text-muted); }\n\n/* --------- Mobile --------- */\n@media (max-width: 640px) {\n  main { padding: 16px 12px 40px; }\n  table.prob td, table.prob th { padding: 10px 8px; font-size: 13px; }\n  table.prob thead th.team-col, table.prob td.team { padding-left: 10px; }\n  table.prob td.num { white-space: nowrap; }\n  .headline { font-size: clamp(28px, 8vw, 40px); }\n}\n\n/* --------- Embed mode (hides header/footer chrome) --------- */\n.embed main { padding: 8px 12px 12px; max-width: 100%; }\n.embed .hero, .embed footer, .embed .tt { display: none; }\n\n/* Mark historical pages with a subtle sepia treatment in the data area */\nbody.historical .table-wrap,\nbody.historical .cross {\n  filter: saturate(0.85) sepia(0.08);\n}\n";
